import{_ as e,c as t,o,d as a}from"./app.5f11fffa.js";const g='{"title":"Vistas y Componentes","description":"","frontmatter":{},"headers":[{"level":2,"title":"Vista Home.vue","slug":"vista-home-vue"},{"level":2,"title":"Vista Register.vue","slug":"vista-register-vue"},{"level":2,"title":"Vista de Login.vue","slug":"vista-de-login-vue"},{"level":2,"title":"Componente Logout.vue","slug":"componente-logout-vue"},{"level":2,"title":"Dashboard View (Protected Path)","slug":"dashboard-view-protected-path"},{"level":2,"title":"Forgot Password View","slug":"forgot-password-view"},{"level":2,"title":"Reset Password View","slug":"reset-password-view"},{"level":2,"title":"Update Password Component","slug":"update-password-component"},{"level":2,"title":"Email Verification","slug":"email-verification"},{"level":2,"title":"Flash Message Component","slug":"flash-message-component"}],"relativePath":"vue/views-and-components.md"}',s={},r=a('<h1 id="vistas-y-componentes" tabindex="-1">Vistas y Componentes <a class="header-anchor" href="#vistas-y-componentes" aria-hidden="true">#</a></h1><p>Aqu\xED hay un desglose de cada uno de los componentes y vistas de Vue que se utilizan para gestionar la autenticaci\xF3n de usuarios, el restablecimiento de contrase\xF1as y la verificaci\xF3n de correo electr\xF3nico.</p><h2 id="vista-home-vue" tabindex="-1">Vista <code>Home.vue</code> <a class="header-anchor" href="#vista-home-vue" aria-hidden="true">#</a></h2><p><a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/src/modules/Auth/views/Home.vue" target="_blank" rel="noopener noreferrer"><strong><code>src/modules/Auth/views/Home.vue</code></strong></a> forma parte del m\xF3dulo <code>Auth</code>. B\xE1sicamente es una pantalla de bienvenida que se le brinda al usuario con la opci\xF3n de elegir dos botones en el caso de que no haya iniciado sesi\xF3n:</p><ol><li><em>&quot;Registrarse&quot;</em></li><li><em>&quot;Iniciar sesi\xF3n&quot;</em></li></ol><p>Esta vista es muy sencilla, sin embargo, ya tiene sus correspondientes pruebas automatizadas para garantizar siempre su buen funcionamiento.</p><ul><li><a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/tests/modules/auth/views/homeMountedCorrectly.spec.ts" target="_blank" rel="noopener noreferrer"><code>tests/modules/auth/views/homeMountedCorrectly.spec.ts</code></a></li><li><a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/tests/modules/auth/views/homeLinksWork.ts" target="_blank" rel="noopener noreferrer"><code>tests/modules/auth/views/homeLinksWork.spec.ts</code></a></li></ul><h2 id="vista-register-vue" tabindex="-1">Vista <code>Register.vue</code> <a class="header-anchor" href="#vista-register-vue" aria-hidden="true">#</a></h2><p><a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/src/modules/Auth/views/Register.vue" target="_blank" rel="noopener noreferrer"><strong><code>src/modules/Auth/views/Register.vue</code></strong></a> permite a los usuarios registrarse para obtener una cuenta si no tienen una. Funciona con el punto final <code>/register</code> de Fortify. Solo funciona cuando un usuario no ha iniciado sesi\xF3n, no puede usarlo para agregar usuarios si ha iniciado sesi\xF3n. Para agregar usuarios a trav\xE9s de una pantalla de administraci\xF3n, necesitar\xEDamos crear otro punto final de API y modificar este componente para publicarlo tambi\xE9n. Por ahora, se mantiene simplemente para registrar nuevos usuarios. Una vez que un usuario se registra correctamente, inicia sesi\xF3n autom\xE1ticamente y se le redirige al panel.</p><p>Esta vista importa dos archivos:</p><ol><li><p><a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/src/modules/Auth/components/FormRegister.vue" target="_blank" rel="noopener noreferrer"><code>src/modules/Auth/components/FormRegister.vue</code></a>: Este componente encapsula el formulario para aser m\xE1s f\xE1cil la prueba de la emisi\xF3n del evento <code>submit</code>.</p></li><li><p><a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/src/modules/Auth/composables/useRegister.ts" target="_blank" rel="noopener noreferrer"><code>src/modules/Auth/composables/useRegister.ts</code></a>: Este composable mantiene la l\xF3gica de negocio separada de la interfaz del usuario.</p></li></ol><p>Y por \xFAltimo las respectivas pruebas automatizadas asociadas a la vista de registro:</p><ul><li><a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/tests/modules/auth/views/registerMountedCorrectly.spec.ts" target="_blank" rel="noopener noreferrer"><code>tests/modules/auth/views/registerMountedCorrectly.spec.ts </code></a></li><li><a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/tests/modules/auth/services/registerFetchMock.spec.ts" target="_blank" rel="noopener noreferrer"><code>tests/modules/auth/services/registerFetchMock.spec.ts</code></a></li><li><a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/tests/modules/auth/components/formRegisterInteractingWith.spec.ts" target="_blank" rel="noopener noreferrer"><code>tests/modules/auth/components/formRegisterInteractingWith.spec.ts</code></a></li><li><a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/tests/modules/auth/components/formRegisterMountedCorrectly.spec.ts" target="_blank" rel="noopener noreferrer"><code>tests/modules/auth/components/formRegisterMountedCorrectly.spec.ts</code></a></li></ul><h2 id="vista-de-login-vue" tabindex="-1">Vista de <code>Login.vue</code> <a class="header-anchor" href="#vista-de-login-vue" aria-hidden="true">#</a></h2><p><a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/src/modules/Auth/views/Login.vue" target="_blank" rel="noopener noreferrer"><strong><code>src/modules/Auth/views/Login.vue</code></strong></a> funciona con el punto final <code>/login</code> de Fortify. Tenga en cuenta que todos los puntos finales de autenticaci\xF3n se mantienen en <a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/src/modules/Auth/services/index.ts" target="_blank" rel="noopener noreferrer"><code>src/modules/Auth/services/index.ts</code></a>. Una vez que un usuario inicia sesi\xF3n correctamente, se le redirige al panel de control.</p><p>Esta vista importa dos archivos:</p><ol><li><p><a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/src/modules/Auth/components/FormLogin.vue" target="_blank" rel="noopener noreferrer"><code>src/modules/Auth/components/FormLogin.vue</code></a>: Este componente encapsula el formulario para aser m\xE1s f\xE1cil la prueba de la emisi\xF3n del evento <code>submit</code>.</p></li><li><p><a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/src/modules/Auth/composables/useLogin.ts" target="_blank" rel="noopener noreferrer"><code>src/modules/Auth/composables/useLogin.ts</code></a>: Este composable mantiene la l\xF3gica de negocio separada de la interfaz del usuario.</p></li></ol><p>Y por \xFAltimo las respectivas pruebas automatizadas asociadas a la vista de inicio de sesi\xF3n:</p><ul><li><a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/tests/modules/auth/views/loginMountedCorrectly.spec.ts" target="_blank" rel="noopener noreferrer"><code>tests/modules/auth/views/loginMountedCorrectly.spec.ts </code></a></li><li><a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/tests/modules/auth/services/loginFetchMock.spec.ts" target="_blank" rel="noopener noreferrer"><code>tests/modules/auth/services/loginFetchMock.spec.ts</code></a></li><li><a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/tests/modules/auth/components/formLoginInteractingWith.spec.ts" target="_blank" rel="noopener noreferrer"><code>tests/modules/auth/components/formLoginInteractingWith.spec.ts</code></a></li><li><a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/tests/modules/auth/components/formLoginMountedCorrectly.spec.ts" target="_blank" rel="noopener noreferrer"><code>tests/modules/auth/components/formLoginMountedCorrectly.spec.ts</code></a></li></ul><h2 id="componente-logout-vue" tabindex="-1">Componente <code>Logout.vue</code> <a class="header-anchor" href="#componente-logout-vue" aria-hidden="true">#</a></h2><p><a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/src/modules/Auth/components/Logout.vue" target="_blank" rel="noopener noreferrer"><strong><code>src/modules/Auth/components/Logout.vue</code></strong></a> Es un componente simple que funciona con el punto final <code>/logout</code> de Fortify. Cuando se cierra la sesi\xF3n de un usuario, se env\xEDa la acci\xF3n de <code>authStore.logout()</code> que borra al usuario del <code>Store</code> y lo redirige a la vista de inicio de sesi\xF3n.</p><h2 id="dashboard-view-protected-path" tabindex="-1">Dashboard View (Protected Path) <a class="header-anchor" href="#dashboard-view-protected-path" aria-hidden="true">#</a></h2><p><a href="https://github.com/garethredfern/laravel-vue/blob/main/src/views/Dashboard.vue" target="_blank" rel="noopener noreferrer">View file on GitHub</a></p><p>This component requires authentication before it can be used. A board could show much more, but the important thing here is that it is protected. A user must be registered to view it.</p><h2 id="forgot-password-view" tabindex="-1">Forgot Password View <a class="header-anchor" href="#forgot-password-view" aria-hidden="true">#</a></h2><p><a href="https://github.com/garethredfern/laravel-vue/blob/main/src/views/ForgotPassword.vue" target="_blank" rel="noopener noreferrer">View file on GitHub</a></p><p>The forgot password view can be accessed if a user is not logged in and needs to reset their password. It works with the Fortify /forgot-password endpoint. Once the form is submitted Laravel will check the email is valid and send out a reset password email. The link in this email will have a token and the URL will point to the reset password view in the SPA.</p><h2 id="reset-password-view" tabindex="-1">Reset Password View <a class="header-anchor" href="#reset-password-view" aria-hidden="true">#</a></h2><p><a href="https://github.com/garethredfern/laravel-vue/blob/main/src/views/ResetPassword.vue" target="_blank" rel="noopener noreferrer">View file on GitHub</a></p><p>The reset password view displays a form where a user can change their password. Importantly it will also have access to the token provided by Laravel. It works with the Fortify /reset-password endpoint. When the form is submitted the users email and token are checked by Laravel. If everything was successful, a message is displayed and the user can log in.</p><h2 id="update-password-component" tabindex="-1">Update Password Component <a class="header-anchor" href="#update-password-component" aria-hidden="true">#</a></h2><p><a href="https://github.com/garethredfern/laravel-vue/blob/main/src/components/UpdatePassword.vue" target="_blank" rel="noopener noreferrer">View file on GitHub</a></p><p>This form allows a logged-in user to update their password. It works with the Fortify /user/password endpoint.</p><h2 id="email-verification" tabindex="-1">Email Verification <a class="header-anchor" href="#email-verification" aria-hidden="true">#</a></h2><p><a href="https://github.com/garethredfern/laravel-vue/blob/main/src/components/VerifyEmail.vue" target="_blank" rel="noopener noreferrer">View file on GitHub</a></p><p>Laravel provides the ability for a user to verify their email as an added layer of security. This component works with the /email/verification-notification endpoint. To get the email notification working, there is some set up required within the Laravel API. More detail in these instructions.</p><p>With this in place, the SPA will check a user is verified using the details in the auth Vuex store. If they are not, a button is displayed, when clicked the verification email will be sent by Laravel. The email will have a link to verify and return the user back to the SPA dashboard.</p><h2 id="flash-message-component" tabindex="-1">Flash Message Component <a class="header-anchor" href="#flash-message-component" aria-hidden="true">#</a></h2><p><a href="https://github.com/garethredfern/laravel-vue/blob/main/src/components/FlashMessage.vue" target="_blank" rel="noopener noreferrer">View file on GitHub</a></p><p>While the user is interacting with the API via the SPA we need to give them success and error messages. The Laravel API will be handling a lot of these messages, but we can also use catch try/catch blocks to display messages within the SPA. To keep things all in one place there is a FlashMessage component which takes a message and error prop.</p>',40),i=[r];function n(l,d,c,u,h,p){return o(),t("div",null,i)}var b=e(s,[["render",n]]);export{g as __pageData,b as default};
